tlScenegraphTransformChunk::tlScenegraphTransformChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::SceneGraph::TRANSFORM);
    ident = Pure3D::SceneGraph::TRANSFORM;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    nchildren = f->GetLong();
    transform.Read(f);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::SceneGraph::TRANSFORM);
    }
}

