tlDataChunk*
tlScenegraphAttachmentPointChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::SceneGraph::BRANCH:
        dch = new tlScenegraphBranchChunk(&ch);
        break;
    case Pure3D::SceneGraph::TRANSFORM:
        dch = new tlScenegraphTransformChunk(&ch);
        break;
    case Pure3D::SceneGraph::DRAWABLE:
        dch = new tlScenegraphDrawableChunk(&ch);
        break;
    case Pure3D::SceneGraph::ATTACHMENT:
        dch = new tlScenegraphAttachmentChunk(&ch);
        break;
    case Pure3D::SceneGraph::CAMERA:
        dch = new tlScenegraphCameraChunk(&ch);
        break;
    case Pure3D::SceneGraph::LIGHTGROUP:
        dch = new tlScenegraphLightGroupChunk(&ch);
        break;
    case Pure3D::SceneGraph::VISIBILITY:
        dch = new tlScenegraphVisibilityChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

